    msgText += `\n\n<i>Nessuna categoria trovata.</i>`;
} else {
    // 3. Costruzione tastiera
    for (let i = 0; i < categories.length; i += 2) {
        let row = [];

        // FIX: Uso .callback_data che contiene l'ID (es: CAT_OO7RNUM2)
        row.push({ 
            text: categories[i].short_name || categories[i].name, 
            callback_data: `m_mkt_list_${categories[i].callback_data}` 
