        message_id: item.body.callback_query.message.message_id,
        text: "⚠️ <b>Errore critico</b>: Categoria non trovata nel catalogo.",
        parse_mode: "HTML",
        reply_markup: { inline_keyboard: [[{ text: "⬅️ Torna al Menu", callback_data: "m_mkt" }]] }
    }}}];
