const categoryName = activeCategory.short_name || activeCategory.name;
const assets = activeCategory.subcategories || [];

let msgText = `🎯 <b>ASSET IN: ${categoryName.toUpperCase()}</b>\n━━━━━━━━━━━━━━━━━━━━\n🟢 = Pronto | ⚪ = Da Ingegnerizzare`;
