const item = $input.first().json;
const owner = item.owner_data || {};
const callbackQuery = item.body.callback_query;
const messageId = callbackQuery.message.message_id; // Recupero message_id
const ghost_id = callbackQuery.data.replace('m_mkt_id_', '');
const baseUrl = item.urlMiniApp;

// --- CONFIGURAZIONE SICUREZZA ASH ---
const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&';
const WEBHOOK_ID = 'ef4aece4-9ec0-4026-a7a7-328562bcbdf6';
const chatId = owner.chat_id.toString();
const timestamp = Date.now().toString();
const payload = `${chatId}|${timestamp}|${WEBHOOK_ID}`;

// Funzione di Firma (Bitwise Hash)
function generateSignature(str, key) {
    let hash = 0;
    const combined = str + key;
    for (let i = 0; i < combined.length; i++) {
        const char = combined.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash = hash & hash; 
    }
    return Math.abs(hash).toString(16);
}

const signature = generateSignature(payload, SECRET_KEY);
const ash = `${Buffer.from(payload).toString('base64')}.${signature}`;
// ------------------------------------

// Lookup nel catalogo per trovare l'asset e la sua categoria di appartenenza
const catalog = item.service_catalog_setup?.categories || [];
let asset = { name: ghost_id, is_ready: false, catId: "" };

for (const cat of catalog) {
    const match = cat.subcategories?.find(s => s.callback_data === ghost_id);
    if (match) { 
        asset = { 
            name: match.name, 
            is_ready: match.blueprint_ready, 
            catId: cat.callback_data 
        }; 
        break; 
    }
}

let msgText = `⚙️ <b>HUB ASSET:</b>\n<code>${asset.name.toUpperCase()}</code>\n━━━━━━━━━━━━━━━━━━━━\n`;
let buttons = [];

if (asset.is_ready) {
    // Se l'asset è pronto (AGGIUNTO message_id all'URL)
    const editKbUrl = `${baseUrl}edit-knowledge.html?sop_id=${ghost_id}&ash=${ash}&message_id=${messageId}`;

    buttons = [
        [{ text: "⚙️ EDITA KNOWLEDGE", web_app: { url: editKbUrl } }],
        [{ text: "📝 Post AI", callback_data: `m_mkt_ask_post_${ghost_id}` }],
        [{ text: "🌐 Deploy SAP", callback_data: `m_mkt_ask_sap_${ghost_id}` }],
        [{ text: "📣 Broadcast", callback_data: `m_mkt_ask_broad_${ghost_id}` }]
    ];
} else {
    // Se l'asset NON è pronto (AGGIUNTO message_id all'URL)
    msgText += `⚠️ <b>CONOSCENZA ASSENTE</b>\nL'asset deve essere ingegnerizzato prima di poter generare contenuti.`;

    const forgeUrl = `${baseUrl}add-product.html?ash=${ash}&catId=${asset.catId}&ghostId=${ghost_id}&msg_id=${messageId}`;

    buttons = [
        [{ text: "⚒️ FORGE KNOWLEDGE", web_app: { url: forgeUrl } }]
    ];
}

// Tasto di ritorno
buttons.push([
    { text: "⬅️ Torna alla Lista", callback_data: `m_mkt_list_${asset.catId}` }
]);

// --- AGGIUNTA PULSANTE HOME GLOBALE ---
buttons.push([
    { text: "🏠 Home", callback_data: "agent_selection" }
]);

return [{ json: { ...item, telegramApiPayload: {
    method: "editMessageText", 
    chat_id: owner.chat_id, 
    message_id: messageId,
    text: msgText, 
    parse_mode: "HTML", 
    reply_markup: { inline_keyboard: buttons }
}}}];

