const cbData = item.body?.callback_query?.data || "";
const chatId = item.body?.callback_query?.message?.chat?.id;
const messageId = item.body?.callback_query?.message?.message_id;

// 2. Estrazione ID Dinamica (IL FIX)
// Cerchiamo il pattern SVC_ seguito da lettere/numeri, ignorando cosa c'è prima
const ghostIdMatch = cbData.match(/SVC_[A-Z0-9]+/);
const ghostId = ghostIdMatch ? ghostIdMatch[0] : null;

let foundCatId = null;
let procedureName = "Procedura";

// 3. Ricerca nel catalogo per trovare la Categoria (CAT_...)
if (catalog.categories && ghostId) {
    for (const cat of catalog.categories) {
        const match = cat.subcategories.find(sub => sub.callback_data === ghostId);
        if (match) {
            foundCatId = cat.callback_data;
            procedureName = match.short_name || match.name;
            break;
        }
    }
}

// 4. Lingua e Testi UI
const rawLang = (owner.lenguage || 'it').toLowerCase();
let lang = rawLang.includes('en') ? 'en' : 'it';

const t = {
  it: {
    title: "⏳ <b>ELABORAZIONE IN CORSO...</b>",
    body: `L'attivazione per <b>"${procedureName}"</b> richiede qualche minuto.\n\n⚠️ Sistema impegnato: non eseguire altre operazioni.`
  },
  en: {
    title: "⏳ <b>PROCESSING...</b>",
    body: `Activation for <b>"${procedureName}"</b> will take a few minutes.\n\n⚠️ System busy: do not perform other operations.`
  }
}[lang];

// 5. Payload Telegram (Freeze UI)
const telegramPayload = {
  method: "editMessageText",
  chat_id: chatId,
  message_id: messageId,
  text: `${t.title}\n━━━━━━━━━━━━━━━━━━━━\n\n${t.body}`,
  parse_mode: "HTML",
  reply_markup: {
    inline_keyboard: [] // Rimuove i pulsanti
  }
};

// 6. Output per la pipe successiva
return [{
  json: {
    ...item,
    user_request: {
      category_id: foundCatId,
      ghost_id: ghostId
    },
    telegramApiPayload: telegramPayload
  }
}];

